import React, { useEffect, useState, useRef } from 'react';
import { playRawAudio } from '../services/audioUtils';
import { Button } from './Button';

interface DictationPlayerProps {
  audioData: string | null;
  status: string;
}

export const DictationPlayer: React.FC<DictationPlayerProps> = ({ audioData, status }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);

  useEffect(() => {
    // Initialize AudioContext only once on mount
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    return () => {
      // Cleanup
      if (sourceNodeRef.current) {
        sourceNodeRef.current.stop();
      }
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, []);

  // Stop audio if test changes or resets
  useEffect(() => {
    if (!audioData && isPlaying) {
      stopAudio();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [audioData]);

  const stopAudio = () => {
    if (sourceNodeRef.current) {
      try {
        sourceNodeRef.current.stop();
      } catch (e) { 
        // Ignore errors if already stopped
      }
      sourceNodeRef.current = null;
    }
    setIsPlaying(false);
  };

  const handlePlay = async () => {
    if (isPlaying) {
      stopAudio();
      return;
    }

    if (!audioData) return;

    setIsPlaying(true);
    sourceNodeRef.current = await playRawAudio(
      audioData, 
      audioContextRef.current,
      () => setIsPlaying(false) // On ended
    );
  };

  if (!audioData) return null;

  return (
    <div className="fixed bottom-6 right-6 z-50 animate-fade-in-up">
      <Button 
        onClick={handlePlay}
        variant={isPlaying ? "danger" : "primary"}
        className="rounded-full shadow-2xl px-6 py-4 flex items-center gap-3 text-lg"
      >
        {isPlaying ? (
          <>
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="currentColor" stroke="none"><rect x="6" y="4" width="4" height="16"></rect><rect x="14" y="4" width="4" height="16"></rect></svg>
            Stop Audio
          </>
        ) : (
          <>
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="currentColor" stroke="none"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>
            Play Dictation
          </>
        )}
      </Button>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { DictationTest, TestStatus } from '../types';

interface ClozeBoardProps {
  test: DictationTest;
  status: TestStatus;
  onAnswerChange: (id: string, value: string) => void;
}

export const ClozeBoard: React.FC<ClozeBoardProps> = ({ test, status, onAnswerChange }) => {
  const inputsRef = useRef<{ [key: string]: HTMLInputElement | null }>({});

  // Focus the first input when the test becomes ready
  useEffect(() => {
    if (status === TestStatus.READY && test.segments.length > 0) {
      const firstInputId = test.segments[0].id;
      if (inputsRef.current[firstInputId]) {
        inputsRef.current[firstInputId]?.focus();
      }
    }
  }, [status, test]);

  const isSubmitted = status === TestStatus.SUBMITTED;

  const getValidationClass = (userAnswer: string, correct: string | null) => {
    if (!isSubmitted || correct === null) return "border-slate-300 focus:border-indigo-500 text-slate-800";

    const isCorrect = userAnswer.trim().toLowerCase() === correct.trim().toLowerCase();
    return isCorrect 
      ? "border-emerald-500 bg-emerald-50 text-emerald-900 font-medium" 
      : "border-red-500 bg-red-50 text-red-900 font-medium line-through";
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-100 p-8 md:p-10 leading-loose text-lg text-slate-700 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold text-slate-800 mb-6 text-center border-b border-slate-100 pb-4">
        {test.title}
      </h1>

      <div className="text-justify font-serif tracking-wide">
        {test.segments.map((segment, index) => (
          <React.Fragment key={segment.id}>
            {/* Text Before Blank */}
            <span dangerouslySetInnerHTML={{ __html: segment.textBefore }} />

            {/* Blank / Input */}
            {segment.wordToFill !== null && (
              <span className="inline-block mx-1 align-baseline relative group">
                {/* The Input Field */}
                <input
                  ref={(el) => (inputsRef.current[segment.id] = el)}
                  type="text"
                  value={segment.userAnswer}
                  onChange={(e) => onAnswerChange(segment.id, e.target.value)}
                  disabled={isSubmitted}
                  className={`
                    bg-transparent border-b-2 outline-none px-1 text-center min-w-[80px] transition-all
                    ${getValidationClass(segment.userAnswer, segment.wordToFill)}
                    disabled:opacity-100
                  `}
                  style={{ width: `${Math.max(segment.userAnswer.length, 6) + 2}ch` }}
                  autoComplete="off"
                  spellCheck={false}
                  placeholder={`(${index + 1})`}
                />

                {/* Correct Answer Tooltip (Shown if incorrect after submit) */}
                {isSubmitted && 
                 segment.wordToFill && 
                 segment.userAnswer.trim().toLowerCase() !== segment.wordToFill.trim().toLowerCase() && (
                  <span className="absolute -top-8 left-1/2 -translate-x-1/2 bg-slate-800 text-white text-xs px-2 py-1 rounded shadow-lg whitespace-nowrap z-10 pointer-events-none opacity-0 group-hover:opacity-100 animate-fade-in transition-opacity">
                    {segment.wordToFill}
                  </span>
                )}

                 {/* Correct Answer Display (Shown always if incorrect after submit - inline correction) */}
                 {isSubmitted && 
                 segment.wordToFill && 
                 segment.userAnswer.trim().toLowerCase() !== segment.wordToFill.trim().toLowerCase() && (
                  <span className="block absolute top-full left-0 w-full text-center text-xs text-emerald-600 font-bold mt-1">
                    {segment.wordToFill}
                  </span>
                )}
              </span>
            )}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { TestControls } from './components/TestControls';
import { ClozeBoard } from './components/ClozeBoard';
import { DictationPlayer } from './components/DictationPlayer';
import { Button } from './components/Button';
import { generateDictationContent, generateSpeech } from './services/geminiService';
import { DictationTest, DictationSegment, TestStatus } from './types';
import { v4 as uuidv4 } from 'uuid'; // Just kidding, I'll use simple random string, avoiding external deps if possible, but actually standard Math.random is fine for this.

const App: React.FC = () => {
  const [status, setStatus] = useState<TestStatus>(TestStatus.IDLE);
  const [testData, setTestData] = useState<DictationTest | null>(null);
  const [audioData, setAudioData] = useState<string | null>(null);
  const [score, setScore] = useState<number | null>(null);

  const parseContentToSegments = (rawText: string): DictationSegment[] => {
    // Regex to find content inside {curly braces}
    const parts = rawText.split(/(\{.*?\})/g);
    const segments: DictationSegment[] = [];

    parts.forEach((part) => {
      if (part.startsWith('{') && part.endsWith('}')) {
        // This is a blank
        const answer = part.slice(1, -1); // Remove braces
        // Attach to previous segment if possible, or create new if starts with blank
        if (segments.length === 0) {
           segments.push({
            id: Math.random().toString(36).substr(2, 9),
            textBefore: "",
            wordToFill: answer,
            userAnswer: ""
          });
        } else {
          // The previous segment gets this answer
          const lastSeg = segments[segments.length - 1];
          if (lastSeg.wordToFill === null) {
              lastSeg.wordToFill = answer;
          } else {
              // Should not happen normally if split works as expected
              // but purely for robustness:
               segments.push({
                id: Math.random().toString(36).substr(2, 9),
                textBefore: "",
                wordToFill: answer,
                userAnswer: ""
              });
          }
        }
      } else {
        // This is normal text
        segments.push({
          id: Math.random().toString(36).substr(2, 9),
          textBefore: part,
          wordToFill: null, // Waiting for next part
          userAnswer: ""
        });
      }
    });

    // Cleanup empty tail segments if any
    return segments.filter(s => s.textBefore || s.wordToFill);
  };

  const handleGenerate = async (topic: string, difficulty: string) => {
    setStatus(TestStatus.GENERATING);
    setScore(null);
    setAudioData(null);
    setTestData(null);

    try {
      // 1. Generate Text
      const contentResponse = await generateDictationContent(topic, difficulty);

      // 2. Parse Segments
      const segments = parseContentToSegments(contentResponse.content);

      // 3. Generate Audio
      // We pass the full clean text to TTS
      const cleanText = contentResponse.content.replace(/\{/g, '').replace(/\}/g, '');
      const audioBase64 = await generateSpeech(cleanText);

      setTestData({
        title: contentResponse.title,
        fullText: cleanText,
        segments: segments
      });
      setAudioData(audioBase64);
      setStatus(TestStatus.READY);

    } catch (error) {
      console.error("Failed to generate test", error);
      alert("Failed to generate test. Please check your API key or try again.");
      setStatus(TestStatus.IDLE);
    }
  };

  const handleAnswerChange = useCallback((id: string, value: string) => {
    setTestData(prev => {
      if (!prev) return null;
      return {
        ...prev,
        segments: prev.segments.map(seg => 
          seg.id === id ? { ...seg, userAnswer: value } : seg
        )
      };
    });
  }, []);

  const handleSubmit = () => {
    if (!testData) return;

    let correctCount = 0;
    let totalBlanks = 0;

    testData.segments.forEach(seg => {
      if (seg.wordToFill) {
        totalBlanks++;
        if (seg.userAnswer.trim().toLowerCase() === seg.wordToFill.trim().toLowerCase()) {
          correctCount++;
        }
      }
    });

    setScore(Math.round((correctCount / totalBlanks) * 100));
    setStatus(TestStatus.SUBMITTED);
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-24">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">D</div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
              Dictation Master
            </h1>
          </div>
          {status === TestStatus.SUBMITTED && score !== null && (
            <div className="flex items-center gap-3">
              <span className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Score</span>
              <span className={`text-2xl font-black ${score >= 80 ? 'text-emerald-600' : score >= 50 ? 'text-yellow-600' : 'text-red-600'}`}>
                {score}%
              </span>
            </div>
          )}
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8 space-y-8">
        <TestControls onGenerate={handleGenerate} isLoading={status === TestStatus.GENERATING} />

        {testData && (
          <div className="animate-fade-in space-y-8">
            <ClozeBoard 
              test={testData} 
              status={status} 
              onAnswerChange={handleAnswerChange} 
            />

            {status !== TestStatus.SUBMITTED ? (
              <div className="flex justify-center pt-4">
                <Button onClick={handleSubmit} variant="success" className="px-12 py-3 text-lg">
                  Submit Answers
                </Button>
              </div>
            ) : (
              <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-6 text-center animate-fade-in">
                <h3 className="text-lg font-bold text-indigo-900 mb-2">Dictation Complete!</h3>
                <p className="text-indigo-700">
                  Review your answers above. Words in <span className="text-emerald-600 font-bold">green</span> are correct. 
                  Mistakes are crossed out in <span className="text-red-600 font-bold">red</span> with the correct answer shown below.
                </p>
                <div className="mt-4">
                   <Button onClick={() => setStatus(TestStatus.READY)} variant="secondary">
                     Retry this Test
                   </Button>
                </div>
              </div>
            )}
          </div>
        )}

        {!testData && status === TestStatus.IDLE && (
          <div className="text-center py-20 text-slate-400">
             <p className="text-lg">Select a topic and generate a test to begin.</p>
          </div>
        )}
      </main>

      <DictationPlayer audioData={audioData} status={status} />
    </div>
  );
};

